-- insert enabled alerts without payload
--  dyn-casepick.


-- Insert warehouse location details for dyn-casepick
insert into app.warehouselocationdetail(description, longdescription, warehouseid, requesttypeid, createdby, lastupdatedby) 
	select rt.description, rt.description, w.warehouseid,  rt.requesttypeid, 'sysuser', 'sysuser' 
		from app.warehouselocation w, app.requesttype rt 
		where w.warehouseshortname not in ('DEFAULTS', 'PRODEV') 
		and rt.description = 'dyn-casepick' 
		and not exists (select 1 from app.warehouselocationdetail r 
							where r.requesttypeid = rt.requesttypeid 
							and r.warehouseid = w.warehouseid);








-- Check if enabled alerts were properly inserted

 
  

select *
	from app.warehouselocationdetail wld, app.warehouselocation wl
	where wld.description like ('%dyn-casepick')
	AND wld.warehouseid = wl.warehouseid 
	order by wl.warehouseshortname






-- insert payload for enabled alerts:

--  dyn-casepick.

--  Named queries (only (ALL) as of writing)
--   ALL

	update app.warehouselocationdetail set payload = '{ "emailContent": {"subject":"Splunk Alert: Mark Dynamic Case Pick","fromEmail":"noreply@rndc-usa.com","toEmail":"wmsinternal@RNDC-USA.COM, WMSMSPSupport@RNDC-USA.COM","sections":[{"htmlHeader":"<h2 style=\"margin:0;\">TBD</h2>"},{"introHtml":"created.in.the.python.code"},{"tableHtml":{"tableHeaders":["create_time", "Item Bulk Import API Status"],"tableRows":[]}},{"footerHtml":"<h2 style=\"margin:0;\">FOOTER.TBD</h2>"}]}, "allOption": [{"sql": "with HEAVY_HIT as (select DOL.ITEM_ID, FLOOR(SUM(DOL.ORIGINAL_ORDERED_QUANTITY/II.EXT_QPC)) as ''TOTAL_QTY'' from default_dcorder.DCO_ORDER DO join default_dcorder.DCO_ORDER_LINE DOL on DO.ORDER_ID = DOL.ORDER_ID and DOL.ORG_ID = %(orgId)s join default_item_master.ITE_ITEM II on DOL.ITEM_ID = II.ITEM_ID and II.PROFILE_ID like concat(%(orgId)s , ''%%'') where DO.org_id = %(orgId)s and ext_region like ''%%R%%'' and DO.order_type = ''Standard'' and DOL.item_id not in (select item_id from default_dcinventory.DCI_LOCATION_ITEM_ASSIGNMENT LIA join default_dcinventory.DCI_LOCATION DL on LIA.LOCATION_ID = DL.LOCATION_ID and DL.PROFILE_ID like concat(%(orgId)s , ''%%'') where org_id = %(orgId)s and DL.STORAGE_UOM_ID in (''PACK'',''UNIT'')) and DO.maximum_status = ''1000'' and II.CONVEYABLE = ''1'' group by DOL.ITEM_ID HAVING SUM(DOL.ORIGINAL_ORDERED_QUANTITY/II.EXT_QPC) >= ''15'' ), ORDERS as (select * from (select DO1.ORDER_ID, DOL1.ORDER_LINE_ID, DOL1.ITEM_ID, DOL1.ORIGINAL_ORDERED_QUANTITY/II.EXT_QPC ''CASES'', ROW_NUMBER() OVER(PARTITION BY item_id ORDER BY order_id desc) as ''RN'' from default_dcorder.DCO_ORDER DO1 join default_dcorder.DCO_ORDER_LINE DOL1 on DO1.ORDER_ID = DOL1.ORDER_ID and DOL1.ORG_ID = %(orgId)s join default_item_master.ITE_ITEM II on DOL1.ITEM_ID = II.ITEM_ID and II.PROFILE_ID like concat(%(orgId)s , ''%%'') where DO1.org_id = %(orgId)s and DO1.maximum_status = ''1000'' and ext_region like ''%%R%%'' and DOL1.item_id in (select DOL.ITEM_ID from default_dcorder.